// ─────────────────────────────────────────────────────────────────────────────
// SECTION 4b · SYMBOL RANK TABLE
// Maps tier ID → symbol array ordered highest→lowest prize value.
// Used by classifyOutcome() to determine which triple tier was hit.
// Only applies to base tiers — self-contained cards manage their own outcomes.
// ─────────────────────────────────────────────────────────────────────────────

const SYMBOL_RANK = {
  haul_ticket:       ['TR','WR','FL','RC','DT','DH'],
  silver_mile:       ['TR','FL','WR','RC','DT','DH'],
  prime_rate_pull:   ['TR','FL','RC','WR','DT','DH'],
  dead_haul_special: ['TR','FL','RC','WR','DT','DH'],
  owner_op_legend:   ['TR','FL','RC','WR','DT','DH'],
};

function classifyOutcome(symbols, tierId) {
  // Self-contained cards don't use this system — return safe default.
  if (!SYMBOL_RANK[tierId]) return 'miss';
  // Count occurrences
  const counts = {};
  symbols.forEach(s => { counts[s] = (counts[s] || 0) + 1; });
  const maxCount = Math.max(...Object.values(counts));

  if (maxCount === 1) return 'miss';
  if (maxCount === 2) return 'any_pair';

  // Triple — rank determines which tier of triple
  const tripleSymbol = Object.keys(counts).find(k => counts[k] === 3);
  const rank = SYMBOL_RANK[tierId].indexOf(tripleSymbol);
  if (rank === 0) return 'grand_triple';
  if (rank <= 2)  return 'mid_triple';
  return 'small_triple';
}

// ─────────────────────────────────────────────────────────────────────────────
// SECTION 7 · CARD GENERATION (odds engine)
// Near-miss architecture: 2-of-3 happens ~38% of the time.
// Full miss (0-of-3): ~22%. Triple: based on tier prize table.
// ─────────────────────────────────────────────────────────────────────────────

// Weighted random pick from array of { value, weight }
function weightedPick(pool) {
  const total = pool.reduce((s, p) => s + p.weight, 0);
  let r = Math.random() * total;
  for (const p of pool) {
    r -= p.weight;
    if (r <= 0) return p.value;
  }
  return pool[pool.length - 1].value;
}

// Outcome probability weights per tier
const OUTCOME_WEIGHTS = {
  haul_ticket:       { miss:22, any_pair:38, small_triple:22, mid_triple:12, grand_triple:6  },
  silver_mile:       { miss:20, any_pair:36, small_triple:22, mid_triple:14, grand_triple:8  },
  prime_rate_pull:   { miss:18, any_pair:34, small_triple:22, mid_triple:16, grand_triple:10 },
  dead_haul_special: { miss:14, any_pair:30, small_triple:24, mid_triple:18, grand_triple:14 },
  owner_op_legend:   { miss:10, any_pair:26, small_triple:24, mid_triple:22, grand_triple:18 },
};

// L3: Legend Bundle owners get a permanent odds boost.
// Miss weight is reduced by ~20% and redistributed to small_triple + any_pair.
// Disclosed in odds.html (required by app store).
function applyLegendOddsBoost(weights) {
  const boost = Math.round(weights.miss * 0.20); // 20% of miss redistributed
  return {
    ...weights,
    miss:         weights.miss - boost,
    any_pair:     weights.any_pair + Math.floor(boost * 0.5),
    small_triple: weights.small_triple + Math.ceil(boost * 0.5),
  };
}

// Generate a 3-symbol result for a given tier
function generateCardSymbols(tierId, legendOddsBoost = false) {
  let weights = OUTCOME_WEIGHTS[tierId];
  // Self-contained cards (jackpot_haul, classic_68, etc.) don't use this system.
  // Return a safe default so the parent component doesn't crash on mount.
  if (!weights) return ['truck', 'truck', 'truck'];
  // L3: Apply Legend Bundle odds boost when active
  if (legendOddsBoost) weights = applyLegendOddsBoost(weights);
  const outcomePool = Object.entries(weights).map(([value, weight]) => ({ value, weight }));
  const outcome = weightedPick(outcomePool);

  const allKeys = SYMBOL_KEYS.slice(); // copy

  // Shuffle helper
  const shuffle = arr => {
    for (let i = arr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [arr[i], arr[j]] = [arr[j], arr[i]];
    }
    return arr;
  };

  let symbols;

  if (outcome === 'miss') {
    // Three distinct symbols
    const picked = shuffle(allKeys.slice()).slice(0, 3);
    symbols = picked;
  } else if (outcome === 'any_pair') {
    // Pick a pair symbol + one different
    const pairKey = allKeys[Math.floor(Math.random() * allKeys.length)];
    const others = allKeys.filter(k => k !== pairKey);
    const third = others[Math.floor(Math.random() * others.length)];
    symbols = shuffle([pairKey, pairKey, third]);
  } else {
    // Triple — pick which triple based on rank
    const rank = SYMBOL_RANK[tierId];
    let tripleKey;
    if (outcome === 'grand_triple') {
      tripleKey = rank[0];
    } else if (outcome === 'mid_triple') {
      tripleKey = rank[Math.floor(Math.random() * 2) + 1];
    } else {
      // small_triple
      tripleKey = rank[Math.floor(Math.random() * 3) + 3];
    }
    symbols = [tripleKey, tripleKey, tripleKey];
  }

  return symbols;
}

// ─────────────────────────────────────────────────────────────────────────────
// SECTION 8 · SERIAL NUMBER ENCODER
// Encodes: prefix + currentDay + level + timestamp hash → unique card ID
// ─────────────────────────────────────────────────────────────────────────────
function generateSerialNumber(tier, currentDay, level) {
  const ts = Date.now();
  const hash = ((ts ^ (currentDay * 7919) ^ (level * 3541)) >>> 0)
    .toString(16).toUpperCase().padStart(6, '0').slice(0, 6);
  const dayStr = String(currentDay).padStart(4, '0');
  return `${tier.serialPrefix}-${dayStr}-${hash}`;
}

