// Get today's fact (rotates by calendar day)
function getTodayFact() {
  const dayOfYear = Math.floor(
    (Date.now() - new Date(new Date().getFullYear(), 0, 0).getTime()) / 86400000
  );
  return INDUSTRY_FACTS[dayOfYear % INDUSTRY_FACTS.length];
}

// ─────────────────────────────────────────────────────────────────────────────
// SECTION 11 · TIER AVAILABILITY LOGIC
// Determines which card tier a player should receive today.
// Owner-Op Legend: hidden, triggers if totalLoads >= 100 AND days since last
// OOL card >= 30. Otherwise: highest unlocked tier.
// ─────────────────────────────────────────────────────────────────────────────
function selectCardTier(level, prestigeLevel, currentDay, lastOOLDay, totalLoadsCompleted) {
  // Owner-Op Legend: hidden, appears once every ~30 game-days IF the player
  // has completed 100+ lifetime loads AND 30+ days have passed since last OOL.
  const daysSinceOOL = lastOOLDay > 0 ? currentDay - lastOOLDay : Infinity;
  const loadsQualify  = (totalLoadsCompleted || 0) >= 100;
  if (daysSinceOOL >= 30 && loadsQualify) {
    // Deterministic per-day trigger — ~1 qualifying day in every 30
    const isOOLDay = ((currentDay * 7 + 13) % 30 === 0);
    if (isOOLDay) return CARD_TIERS[4]; // owner_op_legend
  }

  // Build the card pool based on player progression.
  // All players get the full 5-card free daily variety PLUS tier upgrades.
  // Tier upgrades are weighted into the pool so higher-level players see
  // premium cards more often without losing variety entirely.
  // Prestige players get dead_haul_special mixed into their pool.
  // Self-contained free daily cards — hidden:false with subtitle starting 'Free Daily',
  // filtered by levelReq/prestigeReq so progression-gated cards unlock naturally.
  const FREE_DAILY_SELF = CARD_TIERS.filter(t =>
    t.subtitle.startsWith('Free Daily') && !t.hidden && t.id !== 'haul_ticket' &&
    (t.levelReq || 0) <= level && (t.prestigeReq || 0) <= prestigeLevel
  );

  // Full free daily pool: haul_ticket (always) + all unlocked self-contained daily cards
  const FREE_DAILY = [
    CARD_TIERS[0], // haul_ticket — always-available base tier
    ...FREE_DAILY_SELF,  // jackpot_haul, cash_blitz, triple_7_truck, open_road_daily (Lv0)
                         // gps_turn_left/liftgate_premium (Lv3+), scales_closed_son/aurora_run (Lv5+)
                         // eld_malfunction (Lv7+), paper_log (Lv10+)
  ];

  // Build weighted pool: everyone gets all unlocked free dailies + tier cards by level
  let pool = [...FREE_DAILY]; // base pool: haul_ticket + all unlocked self-contained dailies

  if (level >= 5)  pool.push(CARD_TIERS[1], CARD_TIERS[1]); // silver_mile ×2
  if (level >= 15) pool.push(CARD_TIERS[2], CARD_TIERS[2]); // prime_rate_pull ×2
  if (prestigeLevel >= 1) {
    pool.push(CARD_TIERS[3], CARD_TIERS[3]); // dead_haul_special ×2
    // Prestige players rarely (1/pool.length) see silver/prime mixed in
  }

  // Seed: game day × Knuth multiplicative hash + 5-min wall-clock bucket
  // so the same game-day gives variety across arcade sessions
  const timeBucket = Math.floor(Date.now() / 300000);
  const seed = (currentDay * 2654435761 + timeBucket * 2246822519) >>> 0;
  return pool[seed % pool.length];
}

// ─────────────────────────────────────────────────────────────────────────────
// SECTION 12 · STREAK UTILITIES
// ─────────────────────────────────────────────────────────────────────────────
function getStreakMultiplier(streakDays) {
  if (streakDays >= 7) return 1.25;
  return 1.0;
}

// Apply streak to fold amounts
function applyStreakToFold(amount, streakDays) {
  return Math.round(amount * getStreakMultiplier(streakDays));
}

// ─────────────────────────────────────────────────────────────────────────────
// SECTION 13 · HAPTIC HELPER
// Graceful no-op on devices without vibration.
// ─────────────────────────────────────────────────────────────────────────────
function haptic(pattern) {
  try {
    if (navigator && navigator.vibrate) {
      navigator.vibrate(pattern);
    }
  } catch (_) { /* silent */ }
}

// ─────────────────────────────────────────────────────────────────────────────
// SECTION 13b · WEB AUDIO SOUND ENGINE
// All sounds are procedurally generated — zero external audio files.
// AudioContext is created lazily on first user interaction (browser policy).
// ─────────────────────────────────────────────────────────────────────────────
let _soAudioCtx = null;
function soAC() {
  if (!_soAudioCtx) {
    try {
      _soAudioCtx = new (window.AudioContext || window.webkitAudioContext)();
    } catch (_) { return null; }
  }
  // Resume if suspended (mobile browser policy after inactivity)
  if (_soAudioCtx.state === 'suspended') {
    _soAudioCtx.resume().catch(() => {});
  }
  return _soAudioCtx;
}

// Cooldown tracker so scratch sound doesn't fire > 25x/sec
let _scratchLastFired = 0;

const SOUNDS = {
  // Sand/gravel scratch — fired while finger moves over canvas (~25/sec max)
  scratch() {
    const now = Date.now();
    if (now - _scratchLastFired < 40) return; // 40ms = max 25/sec
    _scratchLastFired = now;
    const ctx = soAC(); if (!ctx) return;
    const t = ctx.currentTime;
    for (let i = 0; i < 6; i++) {
      const start = t + i * 0.006 + Math.random() * 0.004;
      const len   = Math.floor(ctx.sampleRate * 0.018);
      const buf   = ctx.createBuffer(1, len, ctx.sampleRate);
      const d     = buf.getChannelData(0);
      for (let j = 0; j < len; j++) d[j] = (Math.random() * 2 - 1) * Math.sin(j / len * Math.PI);
      const src = ctx.createBufferSource(); src.buffer = buf;
      const bp  = ctx.createBiquadFilter(); bp.type = 'bandpass';
      bp.frequency.value = 700 + Math.random() * 1100; bp.Q.value = 1.5 + Math.random() * 2;
      const g = ctx.createGain(); g.gain.value = 0.14 + Math.random() * 0.18;
      src.connect(bp); bp.connect(g); g.connect(ctx.destination);
      src.start(start); src.stop(start + 0.020);
    }
  },

  // Rising tonal pop when a symbol is revealed
  reveal() {
    const ctx = soAC(); if (!ctx) return;
    const t = ctx.currentTime;
    [440, 660, 880].forEach((freq, i) => {
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'sine'; o.frequency.value = freq;
      g.gain.setValueAtTime(0, t + i * 0.028);
      g.gain.linearRampToValueAtTime(0.14, t + i * 0.028 + 0.020);
      g.gain.exponentialRampToValueAtTime(0.001, t + i * 0.028 + 0.14);
      o.connect(g); g.connect(ctx.destination);
      o.start(t + i * 0.028); o.stop(t + i * 0.028 + 0.18);
    });
  },

  // Near-miss crackle burst — static discharge feel
  nearMiss() {
    const ctx = soAC(); if (!ctx) return;
    const t = ctx.currentTime;
    for (let i = 0; i < 10; i++) {
      const start = t + i * 0.016 + Math.random() * 0.008;
      const len   = Math.floor(ctx.sampleRate * 0.016);
      const buf   = ctx.createBuffer(1, len, ctx.sampleRate);
      const d     = buf.getChannelData(0);
      for (let j = 0; j < len; j++) d[j] = (Math.random() * 2 - 1) * Math.sin(j / len * Math.PI);
      const src = ctx.createBufferSource(); src.buffer = buf;
      const hp  = ctx.createBiquadFilter(); hp.type = 'highpass'; hp.frequency.value = 2200;
      const g   = ctx.createGain(); g.gain.value = 0.22 * (1 - i / 10);
      src.connect(hp); hp.connect(g); g.connect(ctx.destination);
      src.start(start); src.stop(start + 0.018);
    }
  },

  // Win chime — three ascending triangle tones
  win() {
    const ctx = soAC(); if (!ctx) return;
    const t = ctx.currentTime;
    [523, 659, 784].forEach((freq, i) => {
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'triangle'; o.frequency.value = freq;
      g.gain.setValueAtTime(0, t + i * 0.09);
      g.gain.linearRampToValueAtTime(0.20, t + i * 0.09 + 0.030);
      g.gain.exponentialRampToValueAtTime(0.001, t + i * 0.09 + 0.38);
      o.connect(g); g.connect(ctx.destination);
      o.start(t + i * 0.09); o.stop(t + i * 0.09 + 0.45);
    });
  },

  // Jackpot fanfare — 7-note ascending cascade
  jackpot() {
    const ctx = soAC(); if (!ctx) return;
    const t = ctx.currentTime;
    [262, 330, 392, 523, 659, 784, 1047].forEach((freq, i) => {
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'sine'; o.frequency.value = freq;
      g.gain.setValueAtTime(0, t + i * 0.07);
      g.gain.linearRampToValueAtTime(0.22, t + i * 0.07 + 0.030);
      g.gain.exponentialRampToValueAtTime(0.001, t + i * 0.07 + 0.44);
      o.connect(g); g.connect(ctx.destination);
      o.start(t + i * 0.07); o.stop(t + i * 0.07 + 0.52);
    });
  },

  // Miss — single descending tone
  miss() {
    const ctx = soAC(); if (!ctx) return;
    const t = ctx.currentTime;
    const o = ctx.createOscillator(); const g = ctx.createGain();
    o.type = 'sine';
    o.frequency.setValueAtTime(300, t);
    o.frequency.linearRampToValueAtTime(180, t + 0.22);
    g.gain.setValueAtTime(0.18, t);
    g.gain.exponentialRampToValueAtTime(0.001, t + 0.28);
    o.connect(g); g.connect(ctx.destination);
    o.start(t); o.stop(t + 0.32);
  },

  // Reel spin — repeating slot-machine tick played while reels are spinning.
  // Returns a stop() function; caller invokes stop() when last reel settles.
  reelSpin() {
    const ctx = soAC(); if (!ctx) return { stop: () => {} };
    let running = true;
    let nextAt  = ctx.currentTime;
    const INTERVAL = 0.055; // ~18 ticks/sec — slot-machine pace
    function scheduleTick() {
      if (!running) return;
      const t = nextAt;
      // Short broadband click — tonewheel feel
      const len = Math.floor(ctx.sampleRate * 0.012);
      const buf = ctx.createBuffer(1, len, ctx.sampleRate);
      const d   = buf.getChannelData(0);
      for (let i = 0; i < len; i++) d[i] = (Math.random() * 2 - 1) * Math.pow(1 - i / len, 1.8);
      const src2 = ctx.createBufferSource(); src2.buffer = buf;
      const bp   = ctx.createBiquadFilter(); bp.type = 'bandpass';
      bp.frequency.value = 900 + Math.random() * 400; bp.Q.value = 2;
      const g    = ctx.createGain(); g.gain.value = 0.28;
      src2.connect(bp); bp.connect(g); g.connect(ctx.destination);
      src2.start(t); src2.stop(t + 0.015);
      nextAt += INTERVAL;
      // Schedule next tick ~1 frame ahead
      const msUntilNext = Math.max(0, (nextAt - ctx.currentTime) * 1000 - 10);
      setTimeout(scheduleTick, msUntilNext);
    }
    scheduleTick();
    return { stop: () => { running = false; } };
  },

  // Reel stop thud — played when each individual reel settles
  reelStop() {
    const ctx = soAC(); if (!ctx) return;
    const t = ctx.currentTime;
    const len = Math.floor(ctx.sampleRate * 0.030);
    const buf = ctx.createBuffer(1, len, ctx.sampleRate);
    const d   = buf.getChannelData(0);
    for (let i = 0; i < len; i++) d[i] = (Math.random() * 2 - 1) * Math.pow(1 - i / len, 3);
    const src2 = ctx.createBufferSource(); src2.buffer = buf;
    const lp   = ctx.createBiquadFilter(); lp.type = 'lowpass'; lp.frequency.value = 320;
    const g    = ctx.createGain(); g.gain.setValueAtTime(0.45, t); g.gain.exponentialRampToValueAtTime(0.001, t + 0.04);
    src2.connect(lp); lp.connect(g); g.connect(ctx.destination);
    src2.start(t); src2.stop(t + 0.045);
  },

  // Lever pull — mechanical clunk: short broadband thud + metal rattle
  lever() {
    const ctx = soAC(); if (!ctx) return;
    const t = ctx.currentTime;
    // Thud: low-frequency filtered noise burst
    const len = Math.floor(ctx.sampleRate * 0.045);
    const buf = ctx.createBuffer(1, len, ctx.sampleRate);
    const d   = buf.getChannelData(0);
    for (let i = 0; i < len; i++) d[i] = (Math.random() * 2 - 1) * Math.pow(1 - i / len, 2.5);
    const src1 = ctx.createBufferSource(); src1.buffer = buf;
    const lp   = ctx.createBiquadFilter(); lp.type = 'lowpass'; lp.frequency.value = 280;
    const g1   = ctx.createGain(); g1.gain.setValueAtTime(0.55, t); g1.gain.exponentialRampToValueAtTime(0.001, t + 0.06);
    src1.connect(lp); lp.connect(g1); g1.connect(ctx.destination);
    src1.start(t); src1.stop(t + 0.06);
    // Rattle: high-frequency noise burst after thud
    const len2 = Math.floor(ctx.sampleRate * 0.028);
    const buf2 = ctx.createBuffer(1, len2, ctx.sampleRate);
    const d2   = buf2.getChannelData(0);
    for (let i = 0; i < len2; i++) d2[i] = (Math.random() * 2 - 1) * (1 - i / len2);
    const src2 = ctx.createBufferSource(); src2.buffer = buf2;
    const hp   = ctx.createBiquadFilter(); hp.type = 'bandpass'; hp.frequency.value = 1800; hp.Q.value = 1.2;
    const g2   = ctx.createGain(); g2.gain.setValueAtTime(0.22, t + 0.03); g2.gain.exponentialRampToValueAtTime(0.001, t + 0.08);
    src2.connect(hp); hp.connect(g2); g2.connect(ctx.destination);
    src2.start(t + 0.03); src2.stop(t + 0.09);
  },
};

