// Pure CSS particle burst — 24 particles, random trajectories.
// ─────────────────────────────────────────────────────────────────────────────
const ConfettiBurst = memo(function ConfettiBurst() {
  const particles = useMemo(() => {
    const colours = ['#FFD700','#ff4466','#44ffaa','#4499ff','#ff8800','#cc44ff','#ffffff'];
    return Array.from({ length: 24 }, (_, i) => ({
      id:     i,
      color:  colours[i % colours.length],
      left:   `${20 + Math.random() * 60}%`,
      delay:  `${Math.random() * 0.4}s`,
      dur:    `${0.8 + Math.random() * 0.8}s`,
      size:   `${5 + Math.random() * 7}px`,
      rotate: Math.random() > 0.5 ? '1' : '-1',
    }));
  }, []);

  return (
    <div style={{
      position:     'absolute',
      inset:        0,
      pointerEvents:'none',
      overflow:     'hidden',
      zIndex:       10,
    }}>
      {particles.map(p => (
        <div key={p.id} style={{
          position:        'absolute',
          top:             '-5px',
          left:            p.left,
          width:           p.size,
          height:          p.size,
          borderRadius:    2,
          background:      p.color,
          animation:       `soConfetti ${p.dur} ${p.delay} ease-in forwards`,
          transform:       `rotate(${p.rotate === '1' ? 45 : -30}deg)`,
          opacity:         0,
        }} />
      ))}
    </div>
  );
});

