                    {isWin && cell.p > 0 && <div style={{ fontSize: 11, fontWeight: 900, color: TEAL, lineHeight: 1.1 }}>${cell.p}</div>}
                    <div style={{ fontSize: 7.5, color: isWin ? 'rgba(74,240,208,.62)' : isMult ? 'rgba(191,136,255,.6)' : 'rgba(74,240,208,.3)', textTransform: 'uppercase', letterSpacing: 0.3 }}>{cell.l}</div>
