function amRollOutcome() {
  const r = Math.random();
  let syms;
  if      (r < 0.05) { syms = [1, 1, 1]; }
  else if (r < 0.12) { syms = [3, 3, 3]; }
  else if (r < 0.22) { const s = Math.floor(Math.random() * AM_SYMS.length); syms = [s, s, s]; }
  else if (r < 0.48) {
    const s = Math.floor(Math.random() * AM_SYMS.length);
    let o; do { o = Math.floor(Math.random() * AM_SYMS.length); } while (o === s);
    const p = Math.floor(Math.random() * 3);
    syms = p === 0 ? [o, s, s] : p === 1 ? [s, o, s] : [s, s, o];
  } else {
    const used = []; syms = [0, 1, 2].map(() => {
      let i; do { i = Math.floor(Math.random() * AM_SYMS.length); } while (used.includes(i));
      used.push(i); return i;
    });
  }
  return syms;
}

function amGetPrize(syms) {
  const t = syms[0] === syms[1] && syms[1] === syms[2];
  const p = !t && (syms[0] === syms[1] || syms[1] === syms[2] || syms[0] === syms[2]);
  if (t) { const m = AM_SYMS[syms[0]].mult; return m >= 200 ? 2500 : m >= 50 ? 750 : 250; }
  if (p) return 50;
  return 0;
}

function amPaintCover(cv, locked, idx) {
  if (!cv) return;
  const zone = cv.parentElement;
  cv.width  = cv.offsetWidth  || 120;
  cv.height = cv.offsetHeight || 160;
  const ctx = cv.getContext('2d'), W = cv.width, H = cv.height;
  if (locked) {
    ctx.fillStyle = '#010c16'; ctx.fillRect(0, 0, W, H);
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
    ctx.font = `bold 13px ${FONT}`; ctx.fillStyle = 'rgba(0,180,160,.22)';
    ctx.fillText('[LOCKED]', W / 2, H / 2 - 8);
    ctx.font = `9px ${FONT}`; ctx.fillStyle = 'rgba(0,180,160,.18)';
    ctx.fillText(`Scratch zone ${idx} first`, W / 2, H / 2 + 10);
  } else {
    const g = ctx.createLinearGradient(0, 0, W, H);
    g.addColorStop(0, '#01101a'); g.addColorStop(.5, '#010c14'); g.addColorStop(1, '#01101a');
    ctx.fillStyle = g; ctx.fillRect(0, 0, W, H);
    ctx.strokeStyle = 'rgba(0,180,160,.06)'; ctx.lineWidth = 1;
    for (let x = -H; x < W + H; x += 8) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x + H, H); ctx.stroke(); }
    const rg = ctx.createRadialGradient(W*.5, H*.4, 0, W*.5, H*.4, W*.45);
    rg.addColorStop(0, 'rgba(0,180,160,.1)'); rg.addColorStop(1, 'transparent');
    ctx.fillStyle = rg; ctx.fillRect(0, 0, W, H);
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
    ctx.font = `bold 10px ${FONT}`; ctx.fillStyle = 'rgba(0,200,180,.45)';
    ctx.fillText('[ SCRATCH ]', W / 2, H / 2);
  }
}

const AM_EDU = [
  'A 26 ft box truck with a liftgate is one of the most in-demand tools for port ship supply work. Some port jobs have you back your box truck directly alongside a docked vessel \u2014 bumper to hull. You stage ship supplies, spare parts, or marine provisions on your liftgate platform and lower them to the dock. The ship crew then uses the vessel crane to lift the palletized load straight up onto the deck. Know your liftgate capacity (2,000\u20133,000 lbs) and never exceed it.',
  'To enter any secure U.S. maritime port without an escort, you need a TWIC card \u2014 Transportation Worker Identification Credential, issued by the TSA. Apply at tsa.gov/twic or call 855-347-8371 (weekdays 8am\u201310pm ET). Steps: (1) Pre-enroll online. (2) Schedule at a TSA enrollment center (tsaenrollmentbyidemia.tsa.dhs.gov). (3) Bring original ID. (4) Get fingerprinted and photographed. (5) Pay $125.25 (or $93 with HazMat endorsement). Processing takes 30\u201345 days \u2014 apply 60 days before you need it. Valid 5 years.',
  'Port runs in a 26 ft box truck pay a premium because the work is specialized. Box trucks handle ship chandlering \u2014 delivering food, fuel, deck supplies, and parts to vessels. You need a TWIC card ($125.25 at tsa.gov/twic), a liftgate-equipped truck, and knowledge of the terminal appointment system at your port. Rates run $2.50\u20133.10/mile vs standard OTR. Start the TWIC application before you line up the work, not after.',
];

/* Particle layer config for bioluminescent Z-depth effect */
const AM_PARTICLE_LAYERS = [
  { count: 8, sMin: 2,  sMax: 4,  durMin: 6, durMax: 10, anim: 'amDriftFar',   color: 'rgba(0,255,210,.5)',  glow: '0 0 3px rgba(0,255,200,.4)' },
  { count: 6, sMin: 4,  sMax: 7,  durMin: 4, durMax: 7,  anim: 'amDriftMid',   color: 'rgba(0,230,200,.65)', glow: '0 0 5px rgba(0,210,190,.5),0 0 10px rgba(0,180,170,.2)' },
  { count: 4, sMin: 7,  sMax: 12, durMin: 3, durMax: 5,  anim: 'amDriftClose', color: 'rgba(0,255,220,.8)',  glow: '0 0 8px rgba(0,240,210,.6),0 0 16px rgba(0,200,180,.3)' },
];

function AmParticles() {
  const particles = [];
  AM_PARTICLE_LAYERS.forEach(L => {
    for (let i = 0; i < L.count; i++) {
      const sz  = L.sMin + Math.random() * (L.sMax - L.sMin);
      const dur = L.durMin + Math.random() * (L.durMax - L.durMin);
      const delay = -(Math.random() * dur);
      particles.push(
        <div key={`${L.anim}-${i}`} style={{
          position: 'absolute', borderRadius: '50%',
          width: sz, height: sz,
          left: `${5 + Math.random() * 90}%`, bottom: -10,
          background: L.color, boxShadow: L.glow,
          animation: `${L.anim} ${dur}s linear ${delay}s infinite`,
        }} />
      );
    }
  });
  return <div style={{ position: 'absolute', inset: 0, zIndex: 4, pointerEvents: 'none', overflow: 'hidden' }}>{particles}</div>;
}

const AquaMarineCard = memo(function AquaMarineCard({
  onComplete, onClose, level, currentDay, cash,
  setLastDailyScratch, setArcadeEarnedToday,
}) {
  const canvasRefs = [useRef(null), useRef(null), useRef(null)];
  const isDrawing  = useRef(false);
  const revRef     = useRef([false, false, false]);
  const ptrRef = useRef({ drawing: false, zone: -1 });
  const activeZone = useRef(0);

  const [outcome]     = useState(amRollOutcome);
  const [revealed,    setRevealed]    = useState([false, false, false]);
  const [tunkPhase,   setTunkPhase]   = useState(null);
  const [foldAmt,     setFoldAmt]     = useState(0);
  const [tunkMsg,     setTunkMsg]     = useState('');
  const [eduText,     setEduText]     = useState('');
  const [resultMsg,   setResultMsg]   = useState('');
  const [resultIsWin, setResultIsWin] = useState(false);
  const [showStamp,   setShowStamp]   = useState(false);
  const [stampData,   setStampData]   = useState({ word: '', sub: '' });
  const [folded,      setFolded]      = useState(false);
  const [foldPrize,   setFoldPrize]   = useState(0);
  const [done,        setDone]        = useState(false);
  const [serial]      = useState(() =>
    'BTB-AM-' + String(Math.floor(Math.random() * 99999)).padStart(5, '0') + '-D'
  );

  const eduIdxRef = useRef(0);
  const allRevd   = revealed.every(Boolean);
  const [loadMiles]  = useState(() => AM_LOAD_MILES[Math.floor(Math.random() * AM_LOAD_MILES.length)]);
  const [portRate]   = useState(() => AM_PORT_RATES[Math.floor(Math.random() * AM_PORT_RATES.length)]);

  useEffect(() => {
    amPaintCover(canvasRefs[0].current, false, 0);
    [1, 2].forEach(i => {
      amPaintCover(canvasRefs[i].current, true, i);
      if (canvasRefs[i].current) canvasRefs[i].current.style.pointerEvents = 'none';
    });
  }, []);

  const revealZone = useCallback((i) => {
    if (revRef.current[i] || tunkPhase !== null || done || i !== activeZone.current) return;
    revRef.current[i] = true;
    setRevealed(prev => { const n = [...prev]; n[i] = true; return n; });
    const cv = canvasRefs[i].current;
    if (cv) { cv.getContext('2d').clearRect(0, 0, cv.width, cv.height); }
    SOUNDS.scratch();
    if (eduIdxRef.current < AM_EDU.length) setEduText(AM_EDU[eduIdxRef.current++]);
    const rc = revRef.current.filter(Boolean).length;
    if (rc === 1) setTimeout(() => {
      const s = AM_SYMS[outcome[0]];
      setFoldAmt(15);
      setTunkMsg(`First symbol: ${s.lbl} (${s.mult}X). Surface with $15 secured, or dive deeper for the triple.`);
      setTunkPhase(1);
    }, 380);
    else if (rc === 2) setTimeout(() => {
      setFoldAmt(25);
      setTunkMsg('Two zones surfaced. Take $25 and ascend, or reveal Zone 3 for the match.');
      setTunkPhase(2);
    }, 380);
    else if (rc === 3) setTimeout(showFinalResult, 450);
  }, [tunkPhase, done, outcome]);

  const showFinalResult = useCallback(() => {
    const prize = amGetPrize(outcome);
    const isWin = prize > 0;
      const labels = ['AQUA TRIPLE 200X', 'TRIPLE 50X', 'TRIPLE MATCH', 'PAIR', 'NO MATCH'];
    const li = prize >= 2500 ? 0 : prize >= 750 ? 1 : prize >= 250 ? 2 : prize >= 50 ? 3 : 4;
    setResultIsWin(isWin);
    setResultMsg(`${isWin ? '\u2605' : '\u2014'} ${labels[li]}${isWin ? ` \u00b7 $${prize.toLocaleString()} CLAIMED` : ' \u00b7 Depth missed'}`);
    if (isWin && prize >= 750) {
      setStampData({ word: prize >= 2500 ? 'TRIPLE!' : 'MATCH!', sub: `$${prize.toLocaleString()} \u00b7 ${serial}` });
      setShowStamp(true);
      setTimeout(() => setShowStamp(false), 2800);
      SOUNDS.jackpot(); haptic([100,50,100,50,150]);
    } else if (isWin) {
      SOUNDS.win(); haptic([40,20,60]);
    } else {
      SOUNDS.miss(); haptic([25]);
    }
  }, [outcome, serial]);

  const handleFold = useCallback(() => {
    setFolded(true); setFoldPrize(foldAmt); setTunkPhase(null);
    setResultIsWin(true);
    setResultMsg(`\u25b8 SURFACED \u00b7 $${foldAmt} secured \u00b7 Depth held`);
  }, [foldAmt]);

  const doScratch = useCallback((i, clientX, clientY) => {
    const refs = Array.isArray(canvasRefs) ? canvasRefs : [canvasRefs];
    const cv = refs[i]?.current ?? refs[i];
    if (!cv) return;
    const r = cv.getBoundingClientRect();
    const x = (clientX - r.left) * (cv.width  / r.width);
    const y = (clientY - r.top)  * (cv.height / r.height);
    const ctx = cv.getContext('2d');
    ctx.save(); ctx.globalCompositeOperation = 'destination-out';
    ctx.beginPath(); ctx.arc(x, y, 26, 0, Math.PI * 2); ctx.fill(); ctx.restore();
    const d = ctx.getImageData(0, 0, cv.width, cv.height).data;
    let c = 0; for (let p = 3; p < d.length; p += 4) if (d[p] < 10) c++;
    if (c / (cv.width * cv.height) >= 0.50) revealZone(i);
  }, [revealZone]);

  const buildScratch = useCallback((i) => {
    if (revRef.current[i]) return;
    const cv = canvasRefs[i]?.current ?? canvasRefs[i];
    if (!cv) return;
    amPaintCover(cv, false, i);
    cv.style.pointerEvents = 'auto';
    const gp = (e) => {
      const r = cv.getBoundingClientRect(), s = e.touches ? e.touches[0] : e;
      return { x: (s.clientX - r.left) * (cv.width / r.width), y: (s.clientY - r.top) * (cv.height / r.height) };
    };
    const sc = (x, y) => {
      if (revRef.current[i]) return;
      const ctx = cv.getContext('2d');
      ctx.save(); ctx.globalCompositeOperation = 'destination-out';
      ctx.beginPath(); ctx.arc(x, y, 26, 0, Math.PI * 2); ctx.fill(); ctx.restore();
      const d = ctx.getImageData(0, 0, cv.width, cv.height).data;
      let cl = 0; for (let p = 3; p < d.length; p += 4) if (d[p] < 10) cl++;
      if (cl / (cv.width * cv.height) >= 0.46) revealZone(i);
    };
    const onTS = (e) => { isDrawing.current = true; const p = gp(e); sc(p.x, p.y); };
    const onTM = (e) => { e.preventDefault(); if (!isDrawing.current) return; const p = gp(e); sc(p.x, p.y); };
    const onTE = () => { isDrawing.current = false; };
    cv.addEventListener('touchstart', onTS, { passive: true });
    cv.addEventListener('touchmove',  onTM, { passive: false });
    cv.addEventListener('touchend',   onTE, { passive: true });
    cv.addEventListener('mousedown',  (e) => { isDrawing.current = true;  const p = gp(e); sc(p.x, p.y); });
    cv.addEventListener('mousemove',  (e) => { if (!isDrawing.current) return; const p = gp(e); sc(p.x, p.y); });
    cv.addEventListener('mouseup',    () => { isDrawing.current = false; });
    cv.addEventListener('mouseleave', () => { isDrawing.current = false; });
  }, [revealZone]);

  const handleScratchOn = useCallback(() => {
    setTunkPhase(null);
    const nextIdx = revRef.current.findIndex(v => !v);
    if (nextIdx !== -1) { activeZone.current = nextIdx; buildScratch(nextIdx); }
  }, []);

  useEffect(() => { buildScratch(0); }, [buildScratch]);

  const revealAll = useCallback(() => {
    [0, 1, 2].forEach((i, delay) => setTimeout(() => {
      if (revRef.current[i]) return;
      activeZone.current = i; setTunkPhase(null); revealZone(i);
    }, delay * 500));
  }, [revealZone]);

  const handleClaim = useCallback(() => {
    if (done) return; setDone(true);
    const prize = folded ? foldPrize : amGetPrize(outcome);
    if (setLastDailyScratch) setLastDailyScratch(new Date().toDateString());
    if (setArcadeEarnedToday && prize > 0) setArcadeEarnedToday(true);
    onComplete({
      cashEarned:   prize,
      tokensEarned: prize > 0 ? Math.max(1, Math.floor(prize / 50)) : 0,
      outcome:      prize >= 750 ? 'win_big' : prize > 0 ? 'win' : 'scratch',
    });
  }, [done, folded, foldPrize, outcome, setLastDailyScratch, setArcadeEarnedToday, onComplete]);

  const currentPrize = folded ? foldPrize : (allRevd ? amGetPrize(outcome) : 0);
  const AQ = 'rgba(0,200,180,';
  const btnBase = {
    padding: 18, borderRadius: 10, fontSize: 16, fontWeight: 900,
    fontFamily: FONT, cursor: 'none', WebkitTapHighlightColor: 'transparent',
    border: '2.5px solid', letterSpacing: .4, transition: 'transform .1s',
  };

  return (
    <div style={{ position: 'relative', fontFamily: FONT, userSelect: 'none' }}>

      {showStamp && (
        <div style={{ position: 'absolute', top: '42%', left: '50%', zIndex: 20,
          pointerEvents: 'none', textAlign: 'center',
          animation: 'amStampIn .52s cubic-bezier(.2,.8,.4,1.2) forwards' }}>
          <div style={{ borderRadius: 6, padding: '12px 24px', transform: 'rotate(1.5deg)',
            border: `4px solid rgba(0,220,200,.7)`, background: 'rgba(0,5,12,.97)',
            boxShadow: `0 0 0 8px ${AQ}.1),0 12px 48px rgba(0,0,0,.97),0 0 40px rgba(0,180,160,.25)` }}>
            <div style={{ fontSize: 28, fontWeight: 900, letterSpacing: 3,
              color: 'rgba(0,245,220,.95)', fontFamily: MONO,
              textShadow: '0 0 18px rgba(0,200,180,.6)' }}>{stampData.word}</div>
            <div style={{ fontSize: 10, color: `${AQ}.55)`, letterSpacing: 2, marginTop: 3 }}>{stampData.sub}</div>
          </div>
        </div>
      )}

      {/* Card */}
      <div data-scratch-zone="1" style={{ position: 'relative', borderRadius: 12,
        overflow: 'hidden', background: '#010810',
        animation: 'amAquaGlow 4s ease-in-out infinite' }}>

        {/* Layered ocean backgrounds */}
        <div style={{ position: 'absolute', inset: 0, zIndex: 0,
          background: `radial-gradient(ellipse at 30% 20%,rgba(0,80,100,.55) 0%,transparent 45%),radial-gradient(ellipse at 75% 65%,rgba(0,60,90,.4) 0%,transparent 40%),radial-gradient(ellipse at 50% 100%,rgba(0,40,70,.6) 0%,transparent 50%),linear-gradient(180deg,#010c14 0%,#010810 30%,#00060e 60%,#010810 100%)` }} />
        {/* Caustic shimmer */}
        <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: '60%',
          zIndex: 1, pointerEvents: 'none',
          backgroundImage: `repeating-linear-gradient(42deg,transparent 0,transparent 18px,rgba(0,200,180,.025) 18px,rgba(0,200,180,.025) 20px),repeating-linear-gradient(-38deg,transparent 0,transparent 22px,rgba(0,180,200,.018) 22px,rgba(0,180,200,.018) 24px)`,
          backgroundSize: '200% auto', animation: 'amCaustic 8s linear infinite' }} />
        <div style={{ position: 'absolute', inset: 0, zIndex: 2, pointerEvents: 'none',
          background: 'linear-gradient(180deg,rgba(0,150,180,.06) 0%,transparent 35%,rgba(0,20,40,.3) 100%)' }} />
        {/* Bioluminescent particles */}
        <AmParticles />
        {/* Vignette */}
        <div style={{ position: 'absolute', inset: 0, zIndex: 5, pointerEvents: 'none',
          background: 'radial-gradient(ellipse at 50% 40%,transparent 30%,rgba(0,0,0,.78) 100%)' }} />

        <div style={{ position: 'relative', zIndex: 6 }}>

          {/* Header */}
          <div style={{ padding: '10px 14px 9px', display: 'flex', alignItems: 'center',
            justifyContent: 'space-between', borderBottom: `1px solid ${AQ}.18)` }}>
            <div>
              <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: 1.5,
                textTransform: 'uppercase', color: `${AQ}.6)` }}>
                Road Boss Pack &middot; $9.99 &middot; Match-3 Tunk
              </div>
              <div style={{ fontSize: 9, color: `${AQ}.22)`, marginTop: 3, fontFamily: MONO }}>
                {serial} &nbsp;|&nbsp; aqua_marine
              </div>
            </div>
            <div style={{ background: 'linear-gradient(135deg,rgba(0,60,80,.6),rgba(0,100,120,.5))',
              border: `1.5px solid ${AQ}.4)`, borderRadius: 8,
              padding: '5px 12px', textAlign: 'center', flexShrink: 0 }}>
              <div style={{ fontSize: 9, fontWeight: 700, color: `${AQ}.55)`,
                letterSpacing: 1.5, textTransform: 'uppercase' }}>AQUA</div>
              <div style={{ fontSize: 15, fontWeight: 900, color: 'rgba(0,240,210,.8)',
                fontFamily: MONO, letterSpacing: 1 }}>MARINE</div>
            </div>
          </div>

          {/* Hero — sonar + title */}
          <div style={{ padding: '16px 14px 12px', borderBottom: `1px solid ${AQ}.14)`,
            display: 'flex', alignItems: 'center', gap: 14 }}>

            {/* Sonar emblem */}
            <div style={{ width: 90, height: 90, borderRadius: '50%', flexShrink: 0,
              position: 'relative',
              background: 'radial-gradient(circle at 50% 50%,rgba(0,30,40,.95) 0%,rgba(0,10,20,.98) 100%)',
              border: `2px solid ${AQ}.35)`,
              boxShadow: `0 0 0 1px rgba(0,100,120,.3),0 0 20px rgba(0,180,160,.15),inset 0 0 30px rgba(0,50,70,.8)` }}>
              {/* Grid rings SVG */}
              <svg style={{ position: 'absolute', inset: 0, width: '100%', height: '100%' }} viewBox="0 0 90 90">
                <line x1="45" y1="4" x2="45" y2="86" stroke="rgba(0,200,180,.1)" strokeWidth=".8"/>
                <line x1="4" y1="45" x2="86" y2="45" stroke="rgba(0,200,180,.1)" strokeWidth=".8"/>
                <circle cx="45" cy="45" r="36" fill="none" stroke="rgba(0,200,180,.1)" strokeWidth=".8"/>
                <circle cx="45" cy="45" r="24" fill="none" stroke="rgba(0,200,180,.1)" strokeWidth=".8"/>
                <circle cx="45" cy="45" r="12" fill="none" stroke="rgba(0,200,180,.1)" strokeWidth=".8"/>
                <circle cx="60" cy="28" r="2" fill="rgba(0,255,180,.6)"/>
                <circle cx="30" cy="58" r="1.5" fill="rgba(0,255,180,.4)"/>
                <circle cx="68" cy="55" r="1" fill="rgba(0,255,180,.3)"/>
              </svg>
              {/* Ping rings */}
              {[0, -1.5].map((delay, k) => (
                <div key={k} style={{ position: 'absolute', inset: 8, borderRadius: '50%',
                  border: `1px solid ${AQ}${k === 0 ? '.45' : '.3'})`,
                  animation: `amSonarPing 3s ease-out ${delay}s infinite` }} />
              ))}
              {/* Depth readout */}
              <div style={{ position: 'absolute', inset: 0, display: 'flex',
                flexDirection: 'column', alignItems: 'center', justifyContent: 'center', zIndex: 2 }}>
                <div style={{ fontSize: 20, fontWeight: 900, color: 'rgba(0,240,210,.9)',
                  fontFamily: MONO, lineHeight: 1,
                  animation: 'amDepthPulse 2s ease-in-out infinite' }}>{loadMiles}</div>
                <div style={{ fontSize: 7, fontWeight: 700, color: `${AQ}.55)`,
                  letterSpacing: 2, textTransform: 'uppercase', marginTop: 2 }}>MILES</div>
                <div style={{ fontSize: 7, color: `${AQ}.5)`, letterSpacing: 1, marginTop: 4 }}>LOAD RANGE</div>
              </div>
              {/* Blip */}
              <div style={{ position: 'absolute', width: 5, height: 5, borderRadius: '50%',
                background: 'rgba(0,255,180,1)', top: 22, left: 58, zIndex: 3,
                boxShadow: '0 0 8px rgba(0,255,180,.8),0 0 16px rgba(0,200,160,.4)',
                animation: 'amDepthPulse 2s ease-in-out infinite' }} />
            </div>

            {/* Title */}
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 10, fontWeight: 700, color: `${AQ}.45)`,
                letterSpacing: 2, textTransform: 'uppercase', marginBottom: 5 }}>
                Road Boss &middot; Match-3 Tunk
              </div>
              <div style={{ fontSize: 38, fontWeight: 900, letterSpacing: -1, lineHeight: .9,
                background: 'linear-gradient(135deg,#00f5d4,#00b8c8,#00e5d0,#0090b0,#00d4c8)',
                backgroundSize: '300% auto', WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
                animation: 'amCaustic 4s linear infinite', fontFamily: MONO }}>
                AQUA<br/>MARINE
              </div>
              <div style={{ fontSize: 11, fontWeight: 700, color: `${AQ}.45)`,
                letterSpacing: 2.5, textTransform: 'uppercase', marginTop: 7, fontFamily: MONO }}>
                MATCH-3 &bull; TUNK &bull; 200X
              </div>
            </div>
          </div>

          {/* Depth stat bar */}
          <div style={{ display: 'flex', gap: 4, padding: '8px 14px',
            background: 'rgba(0,0,0,.35)', borderBottom: `1px solid ${AQ}.1)` }}>
            {[
              ['Box Length', '26ft',      'BOX TRUCK'],
              ['Liftgate',  '2,500',      'LB CAP'],
              ['Port Rate', portRate,     'PER MILE'],
              ['TWIC',      "REQ'D",      'FOR ACCESS'],
            ].map(([lbl, val, unit]) => (
              <div key={lbl} style={{ flex: 1, textAlign: 'center', padding: '6px 4px',
                background: `${AQ}.05)`, border: `1px solid ${AQ}.16)`, borderRadius: 4 }}>
                <div style={{ fontSize: 9, color: `${AQ}.45)`, textTransform: 'uppercase',
                  letterSpacing: .5, fontWeight: 600 }}>{lbl}</div>
                <div style={{ fontSize: 17, fontWeight: 900, color: 'rgba(0,220,200,.8)',
                  fontFamily: MONO, lineHeight: 1.2 }}>{val}</div>
                <div style={{ fontSize: 8, color: `${AQ}.4)`, fontWeight: 600, letterSpacing: .3 }}>{unit}</div>
              </div>
            ))}
          </div>

          {/* Prize strip */}
          <div style={{ display: 'flex', gap: 3, padding: '6px 10px',
            background: 'rgba(0,0,0,.4)', borderBottom: `1px solid ${AQ}.07)` }}>
            {[['Triple 200X','$2,500'],['Triple 50X','$750'],['Triple','$250'],['Pair','$50'],['No Match','$0']].map(([t,v]) => (
              <div key={t} style={{ flex: 1, textAlign: 'center', padding: '7px 2px',
                background: `${AQ}.05)`, border: `1px solid ${AQ}.12)`, borderRadius: 4 }}>
                <div style={{ fontSize: 9, color: `${AQ}.45)`, textTransform: 'uppercase',
                  fontWeight: 600, letterSpacing: .3 }}>{t}</div>
                <div style={{ fontSize: 14, fontWeight: 900, color: 'rgba(0,210,190,.75)', marginTop: 3 }}>{v}</div>
              </div>
            ))}
          </div>

          {/* Scratch zones */}
          <div style={{ padding: '14px 12px 12px', borderBottom: `1px solid ${AQ}.07)` }}>
            <div style={{ fontSize: 10, fontWeight: 700, color: `${AQ}.45)`,
              letterSpacing: 2, textTransform: 'uppercase', textAlign: 'center', marginBottom: 8 }}>
              Match 3 marine symbols — scratch each zone
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 8 }}>
              {[0, 1, 2].map(i => (
                <div key={i} style={{ borderRadius: 10, overflow: 'hidden', position: 'relative',
                  minHeight: 130, border: `1.5px solid ${AQ}.28)`,
                  background: 'rgba(0,15,25,.8)', touchAction: 'none' }}
                  data-scratch-zone="1"
                  onPointerDown={e => {
                    if (revRef.current[i]) return;
                    ptrRef.current.drawing = true; ptrRef.current.zone = i;
                    e.currentTarget.setPointerCapture(e.pointerId);
                    doScratch(i, e.clientX, e.clientY);
                  }}
                  onPointerMove={e => {
                    if (!ptrRef.current.drawing || ptrRef.current.zone !== i) return;
                    doScratch(i, e.clientX, e.clientY);
                  }}
                  onPointerUp={() => { ptrRef.current.drawing = false; }}
                  onPointerCancel={() => { ptrRef.current.drawing = false; }}>
                  <div style={{ position: 'absolute', inset: 0, zIndex: 1,
                    display: 'flex', flexDirection: 'column', alignItems: 'center',
                    justifyContent: 'center', gap: 6, padding: '10px 6px' }}>
                    <div style={{ fontSize: 9, fontWeight: 700, color: `${AQ}.55)`,
                      letterSpacing: .5, textTransform: 'uppercase', fontFamily: MONO }}>
                      Zone {i + 1}
                    </div>
                    <div style={{ width: 44, height: 44, display: 'flex', alignItems: 'center',
                      justifyContent: 'center', margin: '2px auto',
                      animation: revealed[i] ? 'amRevealPop .4s cubic-bezier(.2,.8,.4,1.2) forwards' : 'none' }}>
                      {AM_SYMS[outcome[i]].svg}
                    </div>
                    <div style={{ fontSize: 13, fontWeight: 900,
                      color: `${AQ}.7)`, fontFamily: MONO }}>
                      {AM_SYMS[outcome[i]].mult}X
                    </div>
                  </div>
                  <canvas ref={canvasRefs[i]} style={{ position: 'absolute', inset: 0, zIndex: 2,
                    display: 'block', width: '100%', height: '100%', cursor: 'none', pointerEvents: 'none' }} />
                </div>
              ))}
            </div>
          </div>

          {/* Tunk */}
          {tunkPhase !== null && (
            <div style={{ background: 'rgba(0,5,12,.98)', borderTop: `2px solid ${AQ}.25)`,
              padding: '10px 12px', animation: 'amTunkSlide .3s ease-out' }}>
              <div style={{ fontSize: 10, fontWeight: 800, color: `${AQ}.55)`,
                letterSpacing: 1.5, textTransform: 'uppercase', marginBottom: 5, textAlign: 'center' }}>
                &#9675; Depth Decision
              </div>
              <div style={{ fontSize: 13, color: 'rgba(0,230,210,.75)',
                textAlign: 'center', marginBottom: 9, lineHeight: 1.5 }}>{tunkMsg}</div>
              <div style={{ display: 'flex', gap: 8 }}>
                <button onClick={handleFold} style={{ ...btnBase, flex: 1,
                  background: `${AQ}.07)`, borderColor: `${AQ}.28)`,
                  color: 'rgba(0,210,190,.7)' }}>
                  SURFACE &middot; TAKE ${foldAmt}
                </button>
                <button onClick={handleScratchOn} style={{ ...btnBase, flex: 1,
                  background: `${AQ}.13)`, borderColor: 'rgba(0,220,200,.55)',
                  color: 'rgba(0,245,220,.9)',
                  boxShadow: `0 0 10px ${AQ}.18)` }}>
                  DIVE DEEPER →
                </button>
              </div>
            </div>
          )}

          {/* Result */}
          {resultMsg && (
            <div style={{ padding: '9px 14px', textAlign: 'center', fontSize: 13,
              fontWeight: 800, letterSpacing: .5,
              background: resultIsWin ? `${AQ}.07)` : 'rgba(0,0,0,.25)',
              color: resultIsWin ? 'rgba(0,240,210,.95)' : `${AQ}.45)`,
              animation: 'amSlideUp .3s ease-out' }}>
              {resultMsg}
            </div>
          )}

          {/* Educational */}
          {eduText && (
            <div style={{ padding: '12px 14px', borderTop: `2px solid ${AQ}.12)`,
              animation: 'amSlideUp .3s ease-out' }}>
              <div style={{ fontSize: 10, fontWeight: 800, color: `${AQ}.55)`,
                letterSpacing: 1.5, textTransform: 'uppercase', marginBottom: 5 }}>
                &#9675; Marcus Says
              </div>
              <div style={{ fontSize: 13, color: `${AQ}.65)`, lineHeight: 1.7 }}>
                {eduText}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Action row */}
      <div style={{ background: '#010810', borderRadius: '0 0 12px 12px',
        padding: '8px 10px', display: 'flex', gap: 8 }}>
        {allRevd || folded ? (
          <button onClick={handleClaim} style={{ ...btnBase, flex: 1,
            background: currentPrize > 0
              ? 'linear-gradient(135deg,rgba(0,80,100,.9),rgba(0,180,160,.9),rgba(0,80,100,.9))'
              : 'transparent',
            backgroundSize: '200% 100%',
            borderColor: currentPrize > 0 ? 'rgba(0,220,200,.65)' : `${AQ}.28)`,
            color: currentPrize > 0 ? '#010c14' : `${AQ}.55)`,
            boxShadow: currentPrize > 0 ? `0 0 18px ${AQ}.3)` : 'none',
          }}>
            {currentPrize > 0 ? `CLAIM $${currentPrize.toLocaleString()} →` : 'Return to Arcade'}
          </button>
        ) : (
          <>
            <button onClick={revealAll} style={{ ...btnBase, flex: 1,
              background: 'transparent', borderColor: `${AQ}.28)`, color: `${AQ}.55)` }}>
              &#9675; SCRATCH ALL ZONES
            </button>
            <button onClick={onClose} style={{ ...btnBase, flex: '0 0 54px',
              padding: '18px 0', fontSize: 22, background: 'transparent',
              borderColor: `${AQ}.28)`, color: `${AQ}.55)` }}>
              &#10005;
            </button>
          </>
        )}
      </div>
    </div>
  );
});


