function oolRollOutcome(isLegendBundle = false) {
  // Legend Bundle players always receive the truck — it's their guaranteed prize,
  // revealed dramatically on this card rather than silently at purchase.
  if (isLegendBundle) return OOL_OUTCOMES[0];
  const r = Math.random();
  if (r < 0.03)        return OOL_OUTCOMES[0]; // truck (3% for non-LB)
  else if (r < 0.10)   return OOL_OUTCOMES[1];
  else if (r < 0.28)   return OOL_OUTCOMES[2];
  else if (r < 0.55)   return OOL_OUTCOMES[3];
  else                 return OOL_OUTCOMES[4];
}

