    callAvatar:{ width:38, height:38, borderRadius:'50%', flexShrink:0, display:'flex', alignItems:'center', justifyContent:'center', fontSize:16, background:'rgba(180,80,20,.25)', border:'1.5px solid rgba(220,100,30,.35)' },
    callInfo:{ flex:1, minWidth:0 },
